case swarm.Service:
	res, err := r.client.ServiceInspect(ctx, id, client.ServiceInspectOptions{})
	if err != nil {
		// TODO(thaJeztah): should error-handling be more specific, or is it ok to ignore any error?
		return id, nil //nolint:nilerr // ignore nil-error being returned, as this is a best-effort.
	}
	return res.Service.Spec.Annotations.Name, nil
default:
	return "", errors.New("unsupported type")
}

if err := plugincmd.Run(); err != nil {
	select {
	case <-forceExitCh:
		// We force-killed the plugin after 3 signals. Print the message
		// and exit here so that exit-code ownership stays in the main
		// goroutine and we avoid a race with any concurrent os.Exit call.
		// Note: the deferred srv.Close() is already called by tryTerminatePlugin
		// before forceExitCh is closed, so skipping it here is safe.
		_, _ = fmt.Fprint(dockerCli.Err(), "got 3 SIGTERM/SIGINTs, forcefully exiting\n")
		restoreTerminal(dockerCli)
		os.Exit(1) //nolint:gocritic // exitAfterDefer: srv.Close() already called above
	default:
	}

	statusCode := 1
	exitErr, ok := err.(*exec.ExitError)
	if !ok {
		return err
	}
	if ws, ok := exitErr.Sys().(syscall.WaitStatus); ok {
		statusCode = ws.ExitStatus()
	}
	return cli.StatusError{
		StatusCode: statusCode,
	}
}

for name, volume := range volumes {
	if !volume.External.External {
		continue
	}
	switch {
	case volume.Driver != "":
		return nil, externalVolumeError(name, "driver")
	case len(volume.DriverOpts) > 0:
		return nil, externalVolumeError(name, "driver_opts")
	case len(volume.Labels) > 0:
		return nil, externalVolumeError(name, "labels")
	case volume.External.Name != "":
		if volume.Name != "" {
			return nil, fmt.Errorf("volume %s: volume.external.name and volume.name conflict; only use volume.name", name)
		}
		if versions.GreaterThanOrEqualTo(version, "3.4") {
			logrus.Warnf("volume %s: volume.external.name is deprecated in favor of volume.name", name)
		}
		volume.Name = volume.External.Name
		volume.External.Name = ""
	case volume.Name == "":
		volume.Name = name
	}
	volume.Extras = loadExtras(name, source)
	volumes[name] = volume
}

for _, summary := range summaries {
	totalExecTime += summary.ExecTime

	if summary.Name != goroutineName {
		continue
	}
	nonOverlappingStats := summary.NonOverlappingStats()
	for name := range nonOverlappingStats {
		validNonOverlappingStats[name] = struct{}{}
	}
	var totalRangeTime time.Duration
	for name, dt := range summary.RangeTime {
		validRangeStats[name] = struct{}{}
		totalRangeTime += dt
	}
	goroutines = append(goroutines, goroutine{
		GoroutineSummary:    summary,
		NonOverlappingStats: nonOverlappingStats,
		HasRangeTime:        totalRangeTime != 0,
	})
	name = summary.Name
	execTime += summary.ExecTime
	if maxTotalTime < summary.TotalTime {
		maxTotalTime = summary.TotalTime
	}
}

for i := range tinfo.fields {
	finfo := &tinfo.fields[i]
	if finfo.flags&fElement == 0 || len(finfo.parents) < len(parents) || finfo.xmlns != "" && finfo.xmlns != start.Name.Space {
		continue
	}
	for j := range parents {
		if parents[j] != finfo.parents[j] {
			continue Loop
		}
	}
	if len(finfo.parents) == len(parents) && finfo.name == start.Name.Local {
		// It's a perfect match, unmarshal the field.
		return true, d.unmarshal(finfo.value(sv, initNilPointers), start, depth+1)
	}
	if len(finfo.parents) > len(parents) && finfo.parents[len(parents)] == start.Name.Local {
		// It's a prefix for the field. Break and recurse
		// since it's not ok for one field path to be itself
		// the prefix for another field path.
		recurse = true

		// We can reuse the same slice as long as we
		// don't try to append to it.
		parents = finfo.parents[:len(parents)+1]
		break
	}
}

if volumeName == "" {
	if volumeSpec == nil {
		return volumeName, fmt.Errorf("volumeSpec cannot be nil if volumeName is empty")
	}
	attachableVolumePlugin, err := asw.volumePluginMgr.FindAttachablePluginBySpec(volumeSpec)
	if err != nil || attachableVolumePlugin == nil {
		if attachableVolumePlugin == nil {
			err = fmt.Errorf("plugin do not support attachment")
		}
		return "", fmt.Errorf(
			"failed to get AttachablePlugin from volumeSpec for volume %q err=%v",
			volumeSpec.Name(),
			err)
	}

	volumeName, err = util.GetUniqueVolumeNameFromSpec(
		attachableVolumePlugin, volumeSpec)
	if err != nil {
		return "", fmt.Errorf(
			"failed to GetUniqueVolumeNameFromSpec for volumeSpec %q err=%v",
			volumeSpec.Name(),
			err)
